import React, { useState, useEffect } from 'react';
import styled, { keyframes } from 'styled-components';
import { 
  BarChart3, 
  Users, 
  Code, 
  Database, 
  Cloud, 
  Rocket, 
  AlertCircle, 
  CheckCircle, 
  Clock, 
  Zap,
  TrendingUp,
  DollarSign,
  GitBranch,
  Server,
  HardDrive
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const pulse = keyframes`
  0%, 100% { opacity: 1; }
  50% { opacity: 0.5; }
`;

const fadeIn = keyframes`
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
`;

const Container = styled.div`
  padding: 2rem;
  background: linear-gradient(135deg, #f0f4f8 0%, #e6f7ff 100%);
  min-height: 100vh;
`;

const Header = styled.div`
  margin-bottom: 2rem;
`;

const Title = styled.h1`
  font-size: 2rem;
  font-weight: 700;
  color: #1e293b;
  margin-bottom: 0.5rem;
`;

const Subtitle = styled.p`
  color: #64748b;
  font-size: 1.1rem;
`;

const StatsGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 1.5rem;
  margin-bottom: 2rem;
`;

const StatCard = styled.div`
  background: white;
  border-radius: 1.25rem;
  padding: 1.5rem;
  box-shadow: 0 8px 30px rgba(0, 0, 0, 0.08);
  border: 1px solid #e2e8f0;
  transition: all 0.3s ease;
  
  &:hover {
    transform: translateY(-5px);
    box-shadow: 0 12px 40px rgba(0, 0, 0, 0.12);
  }
`;

const StatHeader = styled.div`
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 1rem;
`;

const StatIcon = styled.div`
  width: 3.5rem;
  height: 3.5rem;
  border-radius: 1rem;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
`;

const StatTitle = styled.h3`
  font-size: 1rem;
  font-weight: 500;
  color: #64748b;
  margin: 0;
`;

const StatValue = styled.div`
  font-size: 2rem;
  font-weight: 700;
  color: #1e293b;
  margin-bottom: 0.5rem;
`;

const StatChange = styled.div`
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-size: 0.9rem;
  font-weight: 500;
  
  &.positive {
    color: #10b981;
  }
  
  &.negative {
    color: #ef4444;
  }
`;

const Section = styled.div`
  background: white;
  border-radius: 1.25rem;
  padding: 2rem;
  box-shadow: 0 8px 30px rgba(0, 0, 0, 0.08);
  border: 1px solid #e2e8f0;
  margin-bottom: 2rem;
  animation: ${fadeIn} 0.5s ease-out;
`;

const SectionHeader = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 1.5rem;
`;

const SectionTitle = styled.h2`
  font-size: 1.5rem;
  font-weight: 600;
  color: #1e293b;
  margin: 0;
`;

const ViewAllButton = styled.button`
  background: #f1f5f9;
  border: none;
  padding: 0.5rem 1rem;
  border-radius: 0.5rem;
  font-size: 0.9rem;
  font-weight: 500;
  cursor: pointer;
  color: #1e293b;
  transition: all 0.2s ease;
  
  &:hover {
    background: #e2e8f0;
  }
`;

const ProjectList = styled.div`
  display: flex;
  flex-direction: column;
  gap: 1rem;
`;

const ProjectItem = styled.div`
  display: flex;
  align-items: center;
  padding: 1.25rem;
  border-radius: 0.75rem;
  border: 1px solid #e2e8f0;
  transition: all 0.2s ease;
  
  &:hover {
    background: #f8fafc;
    border-color: #c7d2fe;
  }
`;

const ProjectIcon = styled.div`
  width: 3rem;
  height: 3rem;
  border-radius: 0.75rem;
  background: #f1f5f9;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #64748b;
  margin-right: 1rem;
`;

const ProjectInfo = styled.div`
  flex: 1;
`;

const ProjectName = styled.h3`
  font-size: 1.1rem;
  font-weight: 600;
  color: #1e293b;
  margin: 0 0 0.25rem 0;
`;

const ProjectMeta = styled.div`
  display: flex;
  gap: 1rem;
  font-size: 0.85rem;
  color: #64748b;
`;

const ProjectStatus = styled.div`
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-size: 0.9rem;
  font-weight: 500;
  
  &.completed {
    color: #10b981;
  }
  
  &.building {
    color: #f59e0b;
  }
  
  &.failed {
    color: #ef4444;
  }
`;

const QuickActions = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 1.5rem;
`;

const ActionCard = styled.div`
  background: white;
  border-radius: 1.25rem;
  padding: 1.5rem;
  box-shadow: 0 8px 30px rgba(0, 0, 0, 0.08);
  border: 1px solid #e2e8f0;
  cursor: pointer;
  transition: all 0.3s ease;
  text-align: center;
  
  &:hover {
    transform: translateY(-5px);
    box-shadow: 0 12px 40px rgba(0, 0, 0, 0.12);
  }
`;

const ActionIcon = styled.div`
  width: 4rem;
  height: 4rem;
  border-radius: 1rem;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  margin: 0 auto 1rem;
  font-size: 1.5rem;
`;

const ActionTitle = styled.h3`
  font-size: 1.25rem;
  font-weight: 600;
  color: #1e293b;
  margin: 0 0 0.5rem 0;
`;

const ActionDescription = styled.p`
  color: #64748b;
  font-size: 0.95rem;
  margin: 0;
`;

function Dashboard() {
  const navigate = useNavigate();
  const [projects, setProjects] = useState([
    { id: 1, name: 'E-commerce Platform', framework: 'React + Node.js', status: 'completed', lastUpdated: '2 hours ago' },
    { id: 2, name: 'Analytics Dashboard', framework: 'Vue + Python', status: 'building', lastUpdated: '15 minutes ago' },
    { id: 3, name: 'Mobile App', framework: 'React Native', status: 'completed', lastUpdated: '1 day ago' },
    { id: 4, name: 'Blog Platform', framework: 'Next.js', status: 'failed', lastUpdated: '3 hours ago' }
  ]);
  
  const stats = [
    { title: 'Total Projects', value: '24', change: '+12%', icon: <Code size={24} />, positive: true },
    { title: 'Active Users', value: '1,248', change: '+8.2%', icon: <Users size={24} />, positive: true },
    { title: 'Deployments', value: '86', change: '-2.4%', icon: <Rocket size={24} />, positive: false },
    { title: 'Success Rate', value: '98.7%', change: '+1.2%', icon: <CheckCircle size={24} />, positive: true }
  ];
  
  const quickActions = [
    { 
      title: 'New Project', 
      description: 'Create a new application with AI assistance',
      icon: <Zap size={24} />,
      action: () => navigate('/builder')
    },
    { 
      title: 'AI Chat', 
      description: 'Get help with coding and development',
      icon: <BarChart3 size={24} />,
      action: () => navigate('/ai-chat')
    },
    { 
      title: 'Deploy', 
      description: 'Deploy your applications to the cloud',
      icon: <Cloud size={24} />,
      action: () => navigate('/deploy')
    },
    { 
      title: 'Integrations', 
      description: 'Connect with external services',
      icon: <GitBranch size={24} />,
      action: () => navigate('/integrations')
    }
  ];
  
  return (
    <Container>
      <Header>
        <Title>Dashboard</Title>
        <Subtitle>Welcome back! Here's what's happening with your projects today.</Subtitle>
      </Header>
      
      <StatsGrid>
        {stats.map((stat, index) => (
          <StatCard key={index}>
            <StatHeader>
              <StatTitle>{stat.title}</StatTitle>
              <StatIcon>
                {stat.icon}
              </StatIcon>
            </StatHeader>
            <StatValue>{stat.value}</StatValue>
            <StatChange className={stat.positive ? 'positive' : 'negative'}>
              {stat.positive ? <TrendingUp size={16} /> : <AlertCircle size={16} />}
              {stat.change}
            </StatChange>
          </StatCard>
        ))}
      </StatsGrid>
      
      <Section>
        <SectionHeader>
          <SectionTitle>Recent Projects</SectionTitle>
          <ViewAllButton onClick={() => navigate('/projects')}>View All</ViewAllButton>
        </SectionHeader>
        <ProjectList>
          {projects.map((project) => (
            <ProjectItem key={project.id}>
              <ProjectIcon>
                <Code size={20} />
              </ProjectIcon>
              <ProjectInfo>
                <ProjectName>{project.name}</ProjectName>
                <ProjectMeta>
                  <span>{project.framework}</span>
                  <span>{project.lastUpdated}</span>
                </ProjectMeta>
              </ProjectInfo>
              <ProjectStatus className={project.status}>
                {project.status === 'completed' && <CheckCircle size={16} />}
                {project.status === 'building' && <Clock size={16} />}
                {project.status === 'failed' && <AlertCircle size={16} />}
                {project.status.charAt(0).toUpperCase() + project.status.slice(1)}
              </ProjectStatus>
            </ProjectItem>
          ))}
        </ProjectList>
      </Section>
      
      <Section>
        <SectionHeader>
          <SectionTitle>Quick Actions</SectionTitle>
        </SectionHeader>
        <QuickActions>
          {quickActions.map((action, index) => (
            <ActionCard key={index} onClick={action.action}>
              <ActionIcon>
                {action.icon}
              </ActionIcon>
              <ActionTitle>{action.title}</ActionTitle>
              <ActionDescription>{action.description}</ActionDescription>
            </ActionCard>
          ))}
        </QuickActions>
      </Section>
    </Container>
  );
}

export default Dashboard;
